CREATE TABLE items (
  id VARCHAR(11) PRIMARY KEY,
  status TINYINT, /* 1: PUBLISHED, 2: UNPUBLISHED, 3: DELETED */
  data TEXT,
  pub_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
INSERT INTO "items" ("id","status","data","pub_date","created_at","updated_at") VALUES('sbtDCFmqDzi',3,'{"guid":"sbtDCFmqDzi","itunes:explicit":false,"itunes:block":false,"itunes:episodeType":"full","description":"<p>test</p>","title":"test","image":"microfeed/production/images/item-131f1db6788deaa410040d0f41222e5a.jpg"}','2026-03-25T03:28:01.659Z','2026-03-25 03:28:08','2026-03-25T08:53:09.429Z');
CREATE TABLE settings (
  category VARCHAR(20) PRIMARY KEY,
  data TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
