INSERT INTO "settings" ("category","data","created_at","updated_at") VALUES('customCode','{"currentTheme":"custom","themes":{"custom":{"webFeed":"<main>\n  <section>\n    <div class=\"flex\">\n      {{#icon}}\n      <div class=\"mr-4\">\n        <a href=\"{{icon}}\" target=\"_blank\">\n          <img alt=\"{{title}}\" src=\"{{icon}}\" class=\"img-lg\" loading=\"lazy\"/>\n        </a>\n      </div>\n      {{/icon}}\n      <div>\n        {{#authors}}\n        <div class=\"one-line\">\n          <span title=\"{{name}}\">{{name}}</span>\n        </div>\n        {{/authors}}\n        <div>\n          {{#_microfeed.subscribe_methods.length}}\n          <div class=\"text-sm mt-4 mb-2\">\n            Subscribe:\n          </div>\n          {{/_microfeed.subscribe_methods.length}}\n          <div class=\"flex flex-wrap\">\n            {{#_microfeed.subscribe_methods}}\n            <a href=\"{{url}}\" class=\"mr-4 mb-2\">\n              <div class=\"flex items-center\">\n                <img src=\"{{image}}\" class=\"img-sm flex-none\" alt=\"{{name}}\" loading=\"lazy\"/>\n                <div class=\"flex-1 ml-1 text-sm hide-mobile\">{{name}}</div>\n              </div>\n            </a>\n            {{/_microfeed.subscribe_methods}}\n          </div>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  {{#description}}\n  <section>\n    <h2 class=\"border-b\">About</h2>\n    <div>{{{description}}}</div>\n  </section>\n  {{/description}}\n\n  <section>\n    <h2 class=\"border-b\">\n      Latest\n    </h2>\n\n    <div>\n      {{^items.length}}\n      No items.\n      {{/items.length}}\n\n      {{#items}}\n      <div class=\"mb-4\">\n        <a href=\"{{_microfeed.web_url}}\" class=\"mb-1\">\n          {{title}}\n          <span class=\"icon-arrow-right\"></span>\n        </a>\n        <div class=\"text-sm\">\n          {{_microfeed.date_published_short}}\n\n          {{#_microfeed.duration_hhmmss}}\n          &middot;\n          <i>{{_microfeed.duration_hhmmss}}</i>\n          {{/_microfeed.duration_hhmmss}}\n        </div>\n      </div>\n      {{/items}}\n    </div>\n\n    <div class=\"flex justify-center mt-4\">\n      {{#_microfeed.items_prev_cursor}}\n      <div class=\"px-2\">\n        <a href=\"?prev_cursor={{_microfeed.items_prev_cursor}}&sort={{_microfeed.items_sort_order}}\"><span\n          class=\"icon-arrow-left\"> Prev</span></a>\n      </div>\n      {{/_microfeed.items_prev_cursor}}\n\n      {{#_microfeed.items_next_cursor}}\n      <div class=\"px-2\">\n        <a href=\"?next_cursor={{_microfeed.items_next_cursor}}&sort={{_microfeed.items_sort_order}}\">Next <span\n          class=\"icon-arrow-right\"></span></a>\n      </div>\n      {{/_microfeed.items_next_cursor}}\n    </div>\n  </section>\n</main>\n","webItem":"<main>\n  <section class=\"mb-4\">\n    <a href=\"/\">\n      <div class=\"icon-arrow-left\">{{items.0.title}}</div>\n    </a>\n  </section>\n\n  <section>\n    <h1>{{items.0.title}}</h1>\n    <div class=\"mb-4 text-sm\">\n      <time>{{items.0._microfeed.date_published_short}}</time>\n      &middot;\n      <a href=\"{{items.0._microfeed.json_url}}\" target=\"_blank\">json</a>\n      &middot;\n      <a href=\"{{items.0._microfeed.rss_url}}\" target=\"_blank\">rss</a>\n    </div>\n\n    <div>\n      {{#items.0._microfeed.is_audio}}\n      <div class=\"text-sm mb-4\">\n        Listen:\n      </div>\n      {{#items.0.attachments}}\n      <audio controls preload=\"metadata\" class=\"w-full\">\n        <source src=\"{{url}}\" type=\"{{mime_type}}\"/>\n        Your browser does not support the audio element.\n      </audio>\n      {{/items.0.attachments}}\n      {{/items.0._microfeed.is_audio}}\n\n      {{#items.0._microfeed.is_video}}\n      <div class=\"text-sm mb-4\">\n        Watch:\n      </div>\n      {{#items.0.attachments}}\n      <video controls preload=\"metadata\" class=\"w-full\">\n        <source src=\"{{url}}\" type=\"{{mime_type}}\"/>\n        Your browser does not support the video element.\n      </video>\n      {{/items.0.attachments}}\n      {{/items.0._microfeed.is_video}}\n\n      {{#items.0._microfeed.is_document}}\n      {{#items.0.attachments}}\n      <a href=\"{{url}}\" target=\"_blank\" rel=\"noopener nofollow\" class=\"font-bold text-lg\">Download file &#8594;</a>\n      {{/items.0.attachments}}\n      {{/items.0._microfeed.is_document}}\n\n      {{#items.0._microfeed.is_external_url}}\n      {{#items.0.attachments}}\n      <a href=\"{{url}}\" target=\"_blank\" rel=\"noopener nofollow\" class=\"font-bold text-lg\">View url &#8594;</a>\n      {{/items.0.attachments}}\n      {{/items.0._microfeed.is_external_url}}\n\n      {{#items.0._microfeed.is_image}}\n      {{#items.0.attachments}}\n      <a href=\"{{url}}\" target=\"_blank\">\n        <img src=\"{{url}}\" width=\"80%\" loading=\"lazy\" />\n      </a>\n      {{/items.0.attachments}}\n      {{/items.0._microfeed.is_image}}\n    </div>\n    <div>\n      {{#_microfeed.subscribe_methods.length}}\n      <div class=\"text-sm mt-4 mb-2\">\n        Subscribe:\n      </div>\n      {{/_microfeed.subscribe_methods.length}}\n      <div class=\"flex flex-wrap\">\n        {{#_microfeed.subscribe_methods}}\n        <a href=\"{{url}}\" class=\"mr-4 mb-2\">\n          <div class=\"flex items-center\">\n            <img src=\"{{image}}\" class=\"img-sm flex-none\" alt=\"{{name}}\" loading=\"lazy\"/>\n            <div class=\"flex-1 ml-1 text-sm hide-mobile\">{{name}}</div>\n          </div>\n        </a>\n        {{/_microfeed.subscribe_methods}}\n      </div>\n    </div>\n  </section>\n\n  <section>\n    <h2 class=\"border-b\">About</h2>\n    <div>\n      {{#items.0.image}}\n      <div class=\"mb-4\">\n        <a href=\"{{items.0.image}}\" target=\"_blank\">\n          <img src={{items.0.image}} width=\"250\" height=\"250\" loading=\"lazy\"/>\n        </a>\n      </div>\n      {{/items.0.image}}\n      {{#items.0.content_html}}\n      <div>{{{items.0.content_html}}}</div>\n      {{/items.0.content_html}}\n    </div>\n  </section>\n</main>\n","webHeader":"<style>\n  /* Inspired by https://www.swyx.io/css-100-bytes */\n  html {\n    max-width: 70ch;\n    padding: 1.5em 0.2em;\n    margin: auto;\n    line-height: 1.75;\n    font-size: 1em;\n    color: #24292f;\n    font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Oxygen-Sans, Ubuntu, Cantarell, \"Helvetica Neue\", sans-serif;\n  }\n\n  section {\n    margin-bottom: 4em;\n  }\n\n  h1 {\n    font-size: 2em;\n  }\n\n  h2 {\n    font-size: 1.5em;\n  }\n\n  h3 {\n    font-size: 1.25em;\n  }\n\n  p, ul, ol {\n    margin-top: 0;\n    margin-bottom: 0.5em;\n  }\n\n  a, a:visited {\n    color: #0997cc;\n    text-decoration: none;\n    font-weight: 500;\n  }\n\n  a:hover {\n    opacity: 65%;\n  }\n\n  img {\n    max-width: 100%;\n  }\n\n  /* Some css classes */\n  .flex {\n    display: flex;\n  }\n\n  .flex-none {\n    flex: none;\n  }\n\n  .flex-1 {\n    flex: 1;\n  }\n\n  .items-center {\n    align-items: center;\n  }\n\n  .justify-center {\n    justify-content: center;\n  }\n\n  .flex-wrap {\n    flex-wrap: wrap;\n  }\n\n  .px-2 {\n    padding-left: 0.5em;\n    padding-right: 0.5em;\n  }\n\n  .mb-1 {\n    margin-bottom: 0.25em;\n  }\n\n  .mb-2 {\n    margin-bottom: 0.5em;\n  }\n\n  .mb-4 {\n    margin-bottom: 1em;\n  }\n\n  .mt-2 {\n    margin-top: 0.5em;\n  }\n\n  .mt-4 {\n    margin-top: 1em;\n  }\n\n  .ml-1 {\n    margin-left: 0.25em;\n  }\n\n  .mr-4 {\n    margin-right: 1em;\n  }\n\n  .one-line {\n    overflow: hidden;\n    display: -webkit-box;\n    -webkit-line-clamp: 1;\n    -webkit-box-orient: vertical;\n  }\n\n  .text-sm {\n    font-size: 0.8em;\n  }\n\n  .text-lg {\n    font-size: 1.25em;\n  }\n\n  .img-lg {\n    max-width: 7.5em;\n    border-radius: 0.8em;\n    box-shadow: 0.2em 0.2em 0.2em #DCDCDC;\n  }\n\n  .img-md {\n    max-width: 3.5em;\n    border-radius: 0.2em;\n    box-shadow: 0.1em 0.1em 0.1em #DCDCDC;\n  }\n\n  .img-sm {\n    max-width: 1em;\n    border-radius: 0.2em;\n  }\n\n  .border-t {\n    border-top: 1px solid #DCDCDC;\n  }\n\n  .border-b {\n    border-bottom: 1px solid #DCDCDC;\n  }\n\n  .text-center {\n    text-align: center;\n  }\n\n  .w-full {\n    width: 100%;\n  }\n\n  .font-bold {\n    font-weight: bold;\n  }\n\n  @media only screen and (max-width: 600px) {\n    .hide-mobile {\n      display: none;\n    }\n  }\n\n  .icon-arrow-left:before {\n    content: \"←\";\n  }\n\n  .icon-arrow-right:before {\n    content: \"→\";\n  }\n</style>\n\n<!-- Lazy load images -->\n<style>\n  @keyframes backgroundColorPalette {\n    0% {\n      background: #DCDCDC;\n    }\n    25% {\n      background: #D3D3D3;\n    }\n    50% {\n      background: #778899;\n    }\n    75% {\n      background: #D3D3D3;\n    }\n    100% {\n      background: #DCDCDC;\n    }\n  }\n\n  .loader {\n    width: 100%;\n    height: 20em;\n    background-color: #DCDCDC;\n    animation-name: backgroundColorPalette;\n    animation-duration: 10s;\n    animation-iteration-count: infinite;\n    animation-direction: alternate;\n  }\n</style>\n<script>\n  document.addEventListener(''DOMContentLoaded'', function () {\n\n    let lazyImageObserver = new IntersectionObserver(function (entries, observer) {\n      entries.forEach(function (entry) {\n        if (entry.isIntersecting) {\n          let lazyImage = entry.target;\n          const newImage = document.createElement(''img'');\n          newImage.src = lazyImage.dataset.src;\n          newImage.onload = function () {\n            lazyImage.classList.remove(\"loader\");\n            const wrapper = document.createElement(''a'');\n            wrapper.setAttribute(''href'', newImage.src);\n            wrapper.setAttribute(''target'', \"_blank\");\n            wrapper.appendChild(newImage.cloneNode(true));\n            if (lazyImage.parentElement) {\n              lazyImage.parentElement.replaceChild(wrapper, lazyImage);\n              lazyImage.remove();\n            }\n          };\n          lazyImageObserver.unobserve(lazyImage);\n        }\n      });\n    });\n\n    const images = document.querySelectorAll(''img:not([loading=lazy])'');\n    for (let i = 0; i < images.length; i++) {\n      images[i].dataset.src = images[i].src;\n      images[i].classList.add(''loader'');\n      images[i].src = \"data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP88eNnPQAJQwNqJHSUZQAAAABJRU5ErkJggg==\";\n      lazyImageObserver.observe(images[i]);\n    }\n\n  }, false);\n\n</script>\n\n","webBodyStart":"<!-- right after <body> tag -->\n","webBodyEnd":"<footer class=\"text-sm border-t text-center mb-4\">\n  <div class=\"mt-4\">\n    {{#_microfeed.copyright}}\n    {{_microfeed.copyright}}\n    {{/_microfeed.copyright}}\n    {{^_microfeed.copyright}}\n    © {{_microfeed.publisher}}\n    {{/_microfeed.copyright}}\n  </div>\n  <div>\n    Powered by <a href=\"https://www.microfeed.org/\" class=\"text-black\">microfeed</a>\n    (a <a class=\"text-black\" href=\"https://www.listennotes.com/\">Listen Notes</a> project)\n  </div>\n</footer>\n","rssStylesheet":"<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<xsl:stylesheet version=\"2.0\" xmlns:xsl=\"http://www.w3.org/1999/XSL/Transform\"\n                xmlns:itunes=\"http://www.itunes.com/dtds/podcast-1.0.dtd\">\n  <xsl:output method=\"html\" version=\"1.0\" encoding=\"UTF-8\" indent=\"yes\"/>\n  <xsl:template match=\"/\">\n    <html xmlns=\"http://www.w3.org/1999/xhtml\">\n      <head>\n        <title>\n          <xsl:value-of select=\"/rss/channel/title\"/>\n          - RSS Feed\n        </title>\n        <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\"/>\n        <style type=\"text/css\">\n          body {\n          font-family: -apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto,\"Helvetica Neue\",Arial,\"Noto\n          Sans\",sans-serif,\"Apple Color Emoji\",\"Segoe UI Emoji\",\"Segoe UI Symbol\",\"Noto Color Emoji\";\n          font-size: 12px;\n          color: rgba(0, 0, 0, 0.80);\n          background: rgba(0, 0, 0, 0.03);\n          padding: 16px;\n          line-height: 170%;\n          }\n\n          h1 {}\n\n          h2, p, a {\n          line-height: 170%;\n          }\n          a, a:link, a:visited {\n            color: #2C2B3D;\n            text-decoration: none;\n            font-weight: bolder;\n          }\n          a:hover {\n            color: #19B7FA;\n          opacity: 0.7;\n          }\n          img {\n            width: 100%;\n          }\n          .container {\n          max-width: 800px;\n          min-height: 600px;\n          margin: 0 auto;\n          background: #fff;\n          padding: 30px;\n          border-radius: 8px;\n          box-shadow: 0 2px 3px fade(black, 10%);\n          border: 1px solid rgba(0, 0, 0, 0.10);\n          }\n          .podcast-image {\n          margin-bottom: 20px;\n          margin-right: 20px;\n          }\n          .podcast-author {\n          color: rgba(0, 0, 0, 0.60);\n          }\n\n          .podcast-description {\n          }\n          .podcast-image img {\n          width: 200px;\n          height: auto;\n          border-radius: 4px;\n          border: 1px solid rgba(0, 0, 0, 0.10);\n          -webkit-box-shadow: rgba(0,0,0,0.1) 0 0 20px;\n          -moz-box-shadow: rgba(0,0,0,0.1) 0 0 20px;\n          box-shadow: rgba(0,0,0,0.1) 0 0 20px;\n          }\n          .podcast-header {\n          margin-bottom: 20px;\n          }\n          .podcast-header-image-title {\n            display: flex;\n          }\n          .category-container {\n            margin-bottom: 16px;\n            font-size: 12px;\n          }\n\n          .category-item {\n            padding: 4px;\n            border: 1px solid gray;\n            margin: 4px;\n            border-radius: 4px;\n            background-color: gray;\n            color: white;\n          }\n          .item {\n          clear: both;\n          border-top: 1px solid rgba(0, 0, 0, 0.10);\n          padding: 24px 0;\n          }\n          audio {\n          width: 100%;\n          border-radius: 4px;\n          }\n          audio:focus {\n          outline: none;\n          }\n          .episode-image img {\n          width: 100px;\n          height: auto;\n          margin: 0 30px 15px 0;\n          border-radius: 5px;\n          }\n          .episode-time {\n          font-size: 12px;\n          color: #8E8E8E;\n          margin-bottom: 1em;\n          }\n          .view-website-link {\n          text-align: left;\n          }\n          .pagination-div {\n            display: flex;\n            justify-content: center;\n            border-top: 1px solid rgba(0, 0, 0, 0.10);\n            padding-top: 40px;\n          }\n          .view-pagination-link {\n            text-align: center;\n            padding-left: 16px;\n            padding-right: 16px;\n            border: solid 1px;\n            border-radius: 4px;\n            margin-left: 8px;\n            margin-right: 8px;\n          }\n\n          .icon-arrow-left:before {\n            content: \"←\";\n          }\n\n          .icon-arrow-right:before {\n            content: \"→\";\n          }\n\n          .footer {\n            font-size: 12px;\n            color: gray;\n            text-align: center;\n            margin-top: 80px;\n          }\n        </style>\n      </head>\n      <body>\n        <div class=\"container\">\n          <div class=\"podcast-header\">\n            <div class=\"podcast-header-image-title\">\n              <div>\n                <xsl:if test=\"/rss/channel/image\">\n                  <div class=\"podcast-image\">\n                    <a>\n                      <xsl:attribute name=\"href\">\n                        <xsl:value-of select=\"/rss/channel/image/link\"/>\n                      </xsl:attribute>\n                      <img>\n                      <xsl:attribute name=\"src\">\n                        <xsl:value-of select=\"/rss/channel/image/url\"/>\n                      </xsl:attribute>\n                      <xsl:attribute name=\"title\">\n                        <xsl:value-of select=\"/rss/channel/image/title\"/>\n                      </xsl:attribute>\n                      </img>\n                    </a>\n                  </div>\n                </xsl:if>\n              </div>\n              <div>\n                <h1>\n                  <xsl:value-of select=\"/rss/channel/title\"/>\n                </h1>\n                <xsl:if test=\"/rss/channel/itunes:author\">\n                  <p>\n                    By\n                    <span class=\"podcast-author\">\n                    <xsl:value-of select=\"/rss/channel/itunes:author\"/>\n                  </span>\n                  </p>\n                </xsl:if>\n                <xsl:if test=\"/rss/channel/itunes:category\">\n                  <div class=\"category-container\">\n                    Categories:\n                    <xsl:for-each select=\"/rss/channel/itunes:category\">\n                      <span class=\"category-item\"><xsl:value-of select=\"@text\"/></span>\n                      <xsl:if test=\"itunes:category/@text\">\n                        <span class=\"category-item\"><xsl:value-of select=\"itunes:category/@text\"/></span>\n                      </xsl:if>\n                    </xsl:for-each>\n                  </div>\n                </xsl:if>\n                <xsl:for-each select=\"/rss/channel/link[not(@rel)]\">\n                  <xsl:if test=\"self::node()\">\n                    <p class=\"view-website-link\">\n                      <a>\n                        <xsl:attribute name=\"href\">\n                          <xsl:value-of select=\"self::node()\"/>\n                        </xsl:attribute>\n                        <xsl:attribute name=\"target\">_blank</xsl:attribute>\n                        Website &#x2192;\n                      </a>\n                    </p>\n                  </xsl:if>\n                </xsl:for-each>\n              </div>\n            </div>\n            <div class=\"podcast-description\">\n              <xsl:value-of select=\"/rss/channel/description\" disable-output-escaping=\"yes\"/>\n            </div>\n          </div>\n          <xsl:for-each select=\"/rss/channel/item\">\n            <div class=\"item\">\n              <h2>\n                <a>\n                  <xsl:attribute name=\"href\">\n                    <xsl:value-of select=\"link\"/>\n                  </xsl:attribute>\n                  <xsl:attribute name=\"target\">_blank</xsl:attribute>\n                  <xsl:value-of select=\"title\"/>\n                  <span class=\"icon-arrow-right\"></span>\n                </a>\n              </h2>\n              <div class=\"episode-time\">\n                <span>\n                  <xsl:value-of select=\"pubDate\"/>\n                </span>\n                <xsl:if test=\"itunes:duration\">\n                &#x02022;\n                <span>\n                  <xsl:value-of select=\"itunes:duration\"/>\n                </span>\n                </xsl:if>\n              </div>\n              <xsl:if test=\"description\">\n                <div>\n                  <xsl:value-of select=\"description\" disable-output-escaping=\"yes\"/>\n                </div>\n              </xsl:if>\n\n              <xsl:choose>\n                <xsl:when test=\"starts-with(enclosure/@type, ''audio'')\">\n                  <audio controls=\"true\" preload=\"none\">\n                    <xsl:attribute name=\"src\">\n                      <xsl:value-of select=\"enclosure/@url\"/>\n                    </xsl:attribute>\n                  </audio>\n                </xsl:when>\n                <xsl:when test=\"starts-with(enclosure/@type, ''text'')\">\n                  <a>\n                    <xsl:attribute name=\"href\">\n                      <xsl:value-of select=\"enclosure/@url\"/>\n                    </xsl:attribute>\n                    View\n                    <span class=\"icon-arrow-right\"></span>\n                  </a>\n                </xsl:when>\n                <xsl:otherwise>\n                  <a>\n                    <xsl:attribute name=\"href\">\n                      <xsl:value-of select=\"enclosure/@url\"/>\n                    </xsl:attribute>\n                    Download\n                    <span class=\"icon-arrow-right\"></span>\n                  </a>\n                </xsl:otherwise>\n              </xsl:choose>\n            </div>\n          </xsl:for-each>\n\n          <div class=\"pagination-div\">\n            <xsl:for-each select=\"/rss/channel/link[@rel]\">\n              <xsl:if test=\"@rel=''prev''\">\n              <div class=\"view-pagination-link\">\n                <a>\n                  <xsl:attribute name=\"href\">\n                    <xsl:value-of select=\"@href\"/>\n                  </xsl:attribute>\n                  <span class=\"icon-arrow-left\"></span> Prev\n                </a>\n              </div>\n              </xsl:if>\n            </xsl:for-each>\n            <xsl:for-each select=\"/rss/channel/link[@rel]\">\n              <xsl:if test=\"@rel=''next''\">\n              <div class=\"view-pagination-link\">\n                <a>\n                  <xsl:attribute name=\"href\">\n                    <xsl:value-of select=\"@href\"/>\n                  </xsl:attribute>\n                  Next <span class=\"icon-arrow-right\"></span>\n                </a>\n              </div>\n              </xsl:if>\n            </xsl:for-each>\n          </div>\n        </div>\n      </body>\n    </html>\n  </xsl:template>\n</xsl:stylesheet>\n"}}}','2026-03-25 03:08:51','2026-03-25T03:29:55.369Z');
CREATE INDEX channels_status on channels (status);
CREATE INDEX channels_is_primary on channels (is_primary);
CREATE INDEX channels_created_at on channels (created_at);
CREATE INDEX channels_updated_at on channels (updated_at);
CREATE INDEX items_pub_date on items (pub_date);
CREATE INDEX items_created_at on items (created_at);
CREATE INDEX items_updated_at on items (updated_at);
CREATE INDEX items_status on items (status);
